module watchdog_timer(  
    input wire clk,  
    input wire reset_signal,  
    input wire [3:0] timeout_period,  
    output reg timeout  
);  
    reg [3:0] watchdog_counter;  

    always @(posedge clk) begin  
        if (reset_signal) begin  
            watchdog_counter <= 0;  
            timeout <= 0;  
        end else if (watchdog_counter < timeout_period) begin  
            watchdog_counter <= watchdog_counter + 1;  
            timeout <= 0;  
        end else begin  
            timeout <= 1;  
        end  
    end  
endmodule
